class RandomPitchShift:
    def __init__(self, sample_rate: int, min_steps: int = -3, max_steps: int = 3, p: float = 0.5):
        self.sr = sample_rate
        self.min_steps = min_steps
        self.max_steps = max_steps
        self.p = p

    def __call__(self, waveform: npt.NDArray):
        if random.random() < self.p:
            n_steps = random.randint(self.min_steps, self.max_steps)
            # Librosa's C-engine handles pitch shift faster than torchaudio
            waveform = librosa.effects.pitch_shift(waveform, sr=self.sr, n_steps=n_steps)

        return waveform

def spec_augment(spec: torch.Tensor, max_time_mask: float = 0.08, max_freq_mask: float = 0.15, num_masks: int = 2) -> torch.Tensor:
    spec = spec.clone()
    n_mels, T = spec.shape
    fill = spec.min()

    for _ in range(num_masks):
        # 1. Randomly choose a width UP TO the maximum allowed width
        max_tw = int(max_time_mask * T)
        if max_tw > 0:
            tw = random.randint(0, max_tw) # Width is now random
            t0 = random.randint(0, T - tw)
            spec[:, t0:t0+tw] = fill

        # 2. Same for frequency
        max_fw = int(max_freq_mask * n_mels)
        if max_fw > 0:
            fw = random.randint(0, max_fw) # Width is now random
            f0 = random.randint(0, n_mels - fw)
            spec[f0:f0+fw, :] = fill

    return spec

