class AudioChunksDataset(Dataset):

    LABELS_EMOTIONS_V1 = [
        "reviewed_frustrated",
        "reviewed_angry",
        "reviewed_sad",
        "reviewed_disgust",
        "reviewed_excited",
        "reviewed_fear",
        "reviewed_neutral",
        "reviewed_surprise",
        "reviewed_happy",
    ]
    LABELS_EMOTIONS_V2 = [
        "merged_negative",
        "merged_sad",
        "merged_positive",
        "merged_neutral"
    ]

    INWORLD_EMOTIONS = [
        "inworld_emotion_fearful",
        "inworld_emotion_neutral",
        "inworld_emotion_sad",
        "inworld_emotion_calm",
        "inworld_emotion_angry",
        "inworld_emotion_happy",
        "inworld_emotion_surprised",
        "inworld_emotion_disgusted",
        "inworld_emotion_tender",
    ]

    TOP_DB = 80

    # Decay windowed repeat audio by a percentage
    WINDOWED_REPEAT_DECAY = 0.8

    def __init__(
        self,
        df_dataset_audio_chunks: pd.DataFrame,
        iemocap_db_path: Path,
        external_audio_db_path: Path,
        sample_rate: int,
        chunk_threshold_seconds: float,
        n_fft: int,
        hop_length: int,
        win_length: int,
        n_mels: int,
        pad_mode: Literal["zero", "windowed_repeat"] = "zero",
        pitch_shift_prob: float = 0.0,
        enable_spec_augment: bool = False,
        melspec_lib: Literal["torchaudio", "librosa"] = "torchaudio",
        emotion_columns_override: list[str] | None = None
    ):
        self.df_dataset_audio_chunks = df_dataset_audio_chunks
        self.iemocap_db_path = iemocap_db_path
        self.external_audio_db_path = external_audio_db_path
        self.sample_rate = sample_rate
        self.chunk_threshold_seconds = chunk_threshold_seconds
        self.n_fft = n_fft
        self.hop_length = hop_length
        self.win_length = win_length
        self.n_mels = n_mels
        self.pad_mode = pad_mode
        self.enable_spec_augment = enable_spec_augment
        self.melspec_lib = melspec_lib

        self.emotion_columns = AudioChunksDataset.LABELS_EMOTIONS_V1 if emotion_columns_override is None else emotion_columns_override

        self.max_frequency = self.sample_rate / 2
        self.maxchunk_sample_frames = int(chunk_threshold_seconds * sample_rate)
        self.max_mel_timeframes = math.floor(self.maxchunk_sample_frames / self.hop_length) + 1

        # Initialize the pitch shift transform only if probability > 0
        if pitch_shift_prob > 0:
            self.pitch_shifter = RandomPitchShift(
                sample_rate=self.sample_rate,
                p=pitch_shift_prob
            )
        else:
            self.pitch_shifter = None

        # Torch audio transforms
        self.mel_spectrogram_transform = T.MelSpectrogram(
            sample_rate=sample_rate,
            n_fft=n_fft,
            hop_length=hop_length,
            win_length=win_length,
            center=True,
            pad_mode="reflect",
            power=2.0,
            norm='slaney',
            n_mels=n_mels,
            mel_scale="htk",
            f_max=self.max_frequency,
        )
        self.amp_to_db_transform = T.AmplitudeToDB(stype="power", top_db=self.TOP_DB)

        # Convert Mel Spectrogram back to Linear Scale (Inverse Mel)
        self.inverse_mel = T.InverseMelScale(
            n_stft=self.n_fft // 2 + 1,
            n_mels=self.n_mels,
            sample_rate=self.sample_rate,
            mel_scale="htk"
        )

        # Use Griffin-Lim to estimate phase and transform to waveform
        self.griffin_lim = T.GriffinLim(
            n_fft=self.n_fft,
            win_length=self.win_length,
            hop_length=self.hop_length,
            power=2.0  # Matches self.mel_spectrogram_transform setting
        )

        self.iemocap_db_conn = None
        self.external_audio_db_conn = None

    @property
    def LABELS_EMOTIONS(self):
        return self.emotion_columns

    def __len__(self):
        return len(self.df_dataset_audio_chunks)

    def __getitem__(self, idx: int):
        audio_array, sr = self.get_item_audio_bytes(idx)

        # Pitch shift
        if self.pitch_shifter is not None:
            audio_array = self.pitch_shifter(audio_array)

        if self.melspec_lib == "librosa":
            # Calculate log mel spectrogram
            mel_spec = librosa.feature.melspectrogram(
                y=audio_array,
                sr=sr,
                n_fft=self.n_fft,
                hop_length=self.hop_length,
                win_length=self.win_length,
                n_mels=self.n_mels,
                fmax=self.max_frequency,
            )

            # Convert power scale → log scale (closer to human hearing)
            log_mel_spec = librosa.power_to_db(mel_spec, ref=np.max)
            features = torch.tensor(log_mel_spec, dtype=torch.float32)
        else:
            audio_tensor = torch.tensor(audio_array, dtype=torch.float32)

            # torchaudio expects (channels, time)
            audio_tensor = audio_tensor.unsqueeze(0) # mono

            mel_specs = self.mel_spectrogram_transform(audio_tensor)

            # Get the mel matrix for the only channel and
            # convert power scale → log scale (closer to human hearing)
            features = self.amp_to_db_transform(mel_specs[0])
            features = features - features.max()  # now in (-80, 0] like librosa

        dataset_row = self.df_dataset_audio_chunks.iloc[idx]
        labels = self._build_labels_tensor(dataset_row)

        if self.enable_spec_augment:
            features = spec_augment(
                spec=features,
                max_time_mask=0.08,  # Max 8% of the timeline
                max_freq_mask=0.12,  # Max 12% of the frequencies
                num_masks=2,         # Applies 2 time and 2 freq masks
            )

        assert features.shape[0] == self.n_mels
        assert features.shape[1] == self.max_mel_timeframes
        assert len(labels) == len(self.LABELS_EMOTIONS)

        return features, labels

    def get_item_audio_bytes(self, idx: int) -> tuple[npt.NDArray, int]:
        dataset_row = self.df_dataset_audio_chunks.iloc[idx]

        start = int(dataset_row["start_sample_offset"])
        end = int(dataset_row["end_sample_offset"])

        if dataset_row["source_dataset_table_name"] == "iemocap_dataset":
            db_row = self._fetch_db_record(dataset_row["source_dataset_row_index"])

            # Decode audio using soundfile
            audio_bytes = db_row["audio_bytes"]
            audio_array, sr = sf.read(io.BytesIO(audio_bytes), dtype="float32")
            sliced_audio = audio_array[start:end]
        else:
            blob_stream = self._fetch_external_audio_db_stream(dataset_row["source_dataset_row_index"])

            # Decode audio using soundfile
            audio_array, sr = sf.read(blob_stream, dtype="float32", start=start, stop=end)

            # Closing the blob stream now that we have audio_array
            blob_stream.close()
            sliced_audio = audio_array

        # Waveform padding
        if len(sliced_audio) < self.maxchunk_sample_frames:
            sliced_audio = self._pad_waveform(sliced_audio, source_waveform=audio_array)

        assert len(sliced_audio) == self.maxchunk_sample_frames

        return sliced_audio, sr

    def play_item_audio(self, idx: int):
        """Get audio without augmentations."""
        audio_array, sr = self.get_item_audio_bytes(idx)
        display(Audio(audio_array, rate=sr))

    def generate_melspectrogram(self, idx: int) -> torch.Tensor:
        features, _ = self[idx]
        return features

    def plot_melspectrogram(self, idx: int, override_spec: torch.Tensor | None = None):
        dataset_row = self.df_dataset_audio_chunks.iloc[idx]
        if dataset_row["source_dataset_table_name"] == "iemocap_dataset":
            db_row = self._fetch_db_record(dataset_row["source_dataset_row_index"])
            major_emotion = dataset_row.get("reviewed_major_emotion", db_row["major_emotion"])
            transcription = dataset_row.get("chunk_transcript", db_row["transcription"])
        else:
            major_emotion = dataset_row["inworld_major_emotion"]
            transcription = dataset_row["chunk_transcript"]

        spec = self.generate_melspectrogram(idx) if override_spec is None else override_spec

        fig, ax = plt.subplots(figsize=(10, 4))

        total_chunk_parts = dataset_row.get("total_chunk_parts")
        chunk_part_idx = dataset_row.get("chunk_part_idx")
        if total_chunk_parts > 0:
            title = f"Chunk {int(chunk_part_idx) + 1} of {int(total_chunk_parts)}"
        else:
            title = "Single-Chunk"
        title += f'  |  {major_emotion}'

        img = ax.imshow(spec.numpy().astype(np.float32), aspect="auto", origin="lower", cmap="magma")
        ax.set_title(title)
        ax.set_xlabel("Time frames")
        ax.set_ylabel("Mel bands")
        plt.colorbar(img, ax=ax, format="%+2.0f dB")

        if transcription:
            plt.suptitle(f'"{transcription.strip()}"', fontsize=11)

        plt.tight_layout()
        plt.show()

    def decode_melspectrogram(self, spec: torch.Tensor):
        # Convert from log-scale (dB) to power scale
        spec_power = 10 ** (spec / 10)

        # Add mono channel and inverse mel-spec
        inv_tensor = spec_power.unsqueeze(0)
        linear_spectrogram = self.inverse_mel(inv_tensor)

        # Clamp to 0.0 to prevent any tiny negative values from the pseudo-inverse projection
        linear_spectrogram = torch.clamp(linear_spectrogram, min=0.0)

        display(Audio(self.griffin_lim(linear_spectrogram).numpy().astype(np.float32), rate=self.sample_rate))

    def get_labels_emotion_name(self, idx: int) -> str:
        return self.LABELS_EMOTIONS[idx]

    def __getstate__(self):
        # When a worker process retrieves an item, _get_*_db_conn() sees that self.*_db_conn is None and safely establishes a fresh SQLite connection local to that worker process.
        state = self.__dict__.copy()
        if "iemocap_db_conn" in state:
            state["iemocap_db_conn"] = None
        if "external_audio_db_conn" in state:
            state["external_audio_db_conn"] = None
        return state

    def __setstate__(self, state):
        # These methods intercept the pickling process, set the unpicklable connection to None for serialization, and restore it on the child workers.
        self.__dict__.update(state)
        self.iemocap_db_conn = None
        self.external_audio_db_conn = None

    def _get_iemocap_db_conn(self):
        if self.iemocap_db_conn is None:
            self.iemocap_db_conn = sqlite3.connect(self.iemocap_db_path)
            self.iemocap_db_conn.row_factory = sqlite3.Row
        return self.iemocap_db_conn

    def _get_external_audio_db_conn(self):
        if self.external_audio_db_conn is None:
            self.external_audio_db_conn = sqlite3.connect(self.external_audio_db_path)
            self.external_audio_db_conn.row_factory = sqlite3.Row
        return self.external_audio_db_conn

    def _fetch_db_record(self, source_row_index: int) -> dict:
        conn = self._get_iemocap_db_conn()
        cursor = conn.cursor()
        cursor.execute(
            "SELECT audio_bytes, transcription, major_emotion FROM iemocap_dataset WHERE row_index = ?",
            (int(source_row_index),),
        )
        db_row = cursor.fetchone()

        if db_row is None:
            raise ValueError(f"Could not find row_index {source_row_index} in IEMOCAP DB.")

        return db_row

    def _fetch_external_audio_db_stream(self, source_row_index: int):
        conn = self._get_external_audio_db_conn()
        cursor = conn.cursor()

        # Fetch only the primary key/rowid, NOT the massive BLOB itself
        cursor.execute(
            "SELECT rowid FROM external_audio_source WHERE source_dataset_row_index = ?",
            (int(source_row_index),),
        )
        row = cursor.fetchone()

        if row is None:
            raise ValueError(f"Could not find source_dataset_row_index {source_row_index}")

        # Internal sqlite rowid
        rowid = row[0]

        # Open an incremental BLOB stream
        # Arguments: blobopen(table_name, column_name, rowid)
        blob_stream = conn.blobopen("external_audio_source", "audio_bytes", rowid)

        # Always close the blob stream when done (or use a context manager)
        return blob_stream


    def _build_labels_tensor(self, row: pd.Series | dict) -> torch.Tensor:
        return torch.tensor(
            [row[emo_col] for emo_col in self.LABELS_EMOTIONS],
            dtype=torch.float32,
        )

    def merge_source_emotions(self):
        if not hasattr(self, 'original_source_df'):
            self.original_source_df = self.df_dataset_audio_chunks.copy()

        # Create new columns by applying the function
        new_features_df = self.original_source_df.apply(AudioChunksDataset.merge_emotions_by_row, axis=1)

        # Join the new columns back to your original DataFrame
        self.df_dataset_audio_chunks = pd.concat([self.original_source_df, new_features_df], axis=1)

    def _pad_waveform(self, sliced_audio: npt.NDArray, source_waveform: npt.NDArray) -> npt.NDArray:
        # Length of the audio chunk left to be padded.
        sliced_audio_length = len(sliced_audio)
        # Produce a new zero-padded array with the expected frame size.
        padded_waveform = np.pad(sliced_audio, (0, self.maxchunk_sample_frames - sliced_audio_length))
        if self.pad_mode == "windowed_repeat":
            padded_waveform = self._pad_with_widowed_repeat(source_waveform, padded_waveform, repeat_start_offset=sliced_audio_length)
        return padded_waveform

    def _pad_with_widowed_repeat(self, source_waveform: npt.NDArray, padded_waveform: npt.NDArray, repeat_start_offset: int) -> npt.NDArray:
        chunk_size_left_to_pad = self.maxchunk_sample_frames - repeat_start_offset

        for i in range(chunk_size_left_to_pad):
            padded_offset = i + repeat_start_offset
            # Using modulo operator to repeat the source waveform as many times as need.
            # e.g. We have a 3 second padded_waveform, but our source_waveform is only 1 second long,
            #      therefore we need to repeat it 2 more times.
            source_offset = i % len(source_waveform)
            padded_waveform[padded_offset] = source_waveform[source_offset] * self.WINDOWED_REPEAT_DECAY

        return padded_waveform


