class DatasetsFactory:

    CHUNKS_MANIFEST_JSON_FILE_NAME = "dataset_audio_chunk_groups.json"
    IEMOCAP_DB_FILE_NAME = "iemocap_dataset_table.db"
    EXTERNAL_DB_FILE_NAME = "external_audio_source_table.db"
    AUDIO_DATASETS_VERSION_FILE_NAME = "audio_datasets_versions.json"
    IEMOCAP_SPEAKERS_PARTITIONS = {
        "train": [
            "Ses03__F",
            "Ses03__M",
            "Ses04__F",
            "Ses04__M",
            "Ses05__F",
            "Ses05__M",
        ],
        "validation": [
            "Ses02__F",
            "Ses02__M",
        ],
        "test": [
            "Ses01__F",
            "Ses01__M",
        ],
    }
    EXTERNAL_AUDIO_SPEAKERS_PARTITIONS = {
        "train": [
            "train-1.wav",
            "train-2.wav",
            "train-3.wav",
            "train-4.wav",
            "train-5.wav",
            "train-6.wav",
            "train-7.wav",
            "train-8.wav",
            "train-9.wav",
            "train-10.wav",
        ],
        "validation": [
            "validation.wav",
        ],
        "test": [
            "test.wav",
        ],
    }
    DATASET_AUDIO_CHUNK_GROUP_ID_V2_CUTOFF = 2
    DATASET_AUDIO_CHUNK_GROUP_ID_INWORLD_CUTOFF = 8

    def __init__(
        self,
        url: str,
        override_cache_dir: Path | None = None,
        refresh_chunks_manifest_json_file: bool = True,
        refresh_iemocap_db_file: bool = True,
        refresh_external_db_file: bool = True,
    ):
        self.url = url.rstrip("/")
        self.cache_dir = (
            Path(override_cache_dir)
            if override_cache_dir
            else Path.home() / ".cache" / "upc-aidl-iemocap-datasets"
        )
        self.cache_dir.mkdir(parents=True, exist_ok=True)

        self.chunks_manifest_json_path = self.cache_dir / self.CHUNKS_MANIFEST_JSON_FILE_NAME
        self.db_version_json_path = self.cache_dir / self.AUDIO_DATASETS_VERSION_FILE_NAME
        self.iemocap_db_path = self.cache_dir / self.IEMOCAP_DB_FILE_NAME
        self.external_audio_db_path = self.cache_dir / self.EXTERNAL_DB_FILE_NAME

        # Mapped CHUNKS_MANIFEST_JSON_FILE_NAME manifest *adding* local parquet file path.
        # {dataset_audio_chunk_groups.id: dataset_audio_chunk_group | _parquet_path, ...}
        self.dataset_audio_chunk_groups = {}

        # Initial download of manifest and DB
        self._sync(refresh_chunks_manifest_json_file, refresh_iemocap_db_file, refresh_external_db_file)

    def clear_cached_files(self):
        """Delete specific cached files: manifest, version JSON, SQLite DBs, and parquet files."""
        if self.chunks_manifest_json_path.exists():
            try:
                with open(self.chunks_manifest_json_path, "r") as f:
                    manifest_data = json.load(f)
                for group in manifest_data:
                    parquet_url = group.get("last_export_filename")
                    if parquet_url:
                        parquet_filename = self._extract_dataset_audio_chunks_file_name(parquet_url)
                        parquet_path = self.cache_dir / parquet_filename
                        if parquet_path.exists():
                            parquet_path.unlink()
            except Exception as e:
                print(f"Error reading manifest during cache clearing: {e}")

        for path in [self.chunks_manifest_json_path, self.db_version_json_path, self.iemocap_db_path, self.external_audio_db_path]:
            if path.exists():
                path.unlink()

    def _should_download_iemocap_db(self, remote_metadata: dict) -> bool:
        if not self.iemocap_db_path.exists():
            return True
        if not remote_metadata:
            return False
        if not self.db_version_json_path.exists():
            return True
        try:
            with open(self.db_version_json_path, "r") as f:
                local_data = json.load(f)
            local_version = local_data.get("iemocap_dataset_version")
            remote_version = remote_metadata.get("iemocap_dataset_version")
            return local_version != remote_version
        except Exception:
            return True

    def _should_download_external_db(self, remote_metadata: dict) -> bool:
        remote_version = remote_metadata.get("external_audio_source_version")
        if remote_version is None:
            return False
        if not self.external_audio_db_path.exists():
            return True
        if not remote_metadata:
            return False
        if not self.db_version_json_path.exists():
            return True
        try:
            with open(self.db_version_json_path, "r") as f:
                local_data = json.load(f)
            local_version = local_data.get("external_audio_source_version")
            return local_version != remote_version
        except Exception:
            return True

    def _update_local_metadata(self, remote_metadata: dict):
        if not remote_metadata:
            return
        local_data = {}
        if self.db_version_json_path.exists():
            try:
                with open(self.db_version_json_path, "r") as f:
                    local_data = json.load(f)
            except Exception:
                pass
        local_data.update(remote_metadata)
        with open(self.db_version_json_path, "w") as f:
            json.dump(local_data, f)

    def _sync(
        self,
        refresh_chunks_manifest_json_file: bool = True,
        refresh_iemocap_db_file: bool = True,
        refresh_external_db_file: bool = True,
    ):
        if refresh_chunks_manifest_json_file or not self.chunks_manifest_json_path.exists():
            print(f"Downloading audio chunk dataset groups manifest...")
            self._download_file(
                f"{self.url}/{self.CHUNKS_MANIFEST_JSON_FILE_NAME}", self.chunks_manifest_json_path, "Audio Chunk Dataset Groups Manifest"
            )

        # Download remote version metadata to check versions
        remote_metadata = {}
        if (refresh_iemocap_db_file and (not self.iemocap_db_path.exists() or not self.db_version_json_path.exists())) or \
           (refresh_external_db_file and (not self.external_audio_db_path.exists() or not self.db_version_json_path.exists())) or \
           refresh_iemocap_db_file or refresh_external_db_file:
            with tempfile.TemporaryDirectory() as temp_dir:
                temp_version_path = Path(temp_dir) / self.AUDIO_DATASETS_VERSION_FILE_NAME
                try:
                    self._download_file(
                        f"{self.url}/{self.AUDIO_DATASETS_VERSION_FILE_NAME}",
                        temp_version_path,
                        "Checking DB Version"
                    )
                    if temp_version_path.exists():
                        with open(temp_version_path, "r") as f:
                            remote_metadata = json.load(f)
                except Exception as e:
                    print(f"Failed to check remote version: {e}.")

        if refresh_iemocap_db_file and self._should_download_iemocap_db(remote_metadata):
            print("Downloading IEMOCAP SQLite database...")
            self._download_file(
                f"{self.url}/{self.IEMOCAP_DB_FILE_NAME}", self.iemocap_db_path, "IEMOCAP SQLite DB"
            )
            self._update_local_metadata(remote_metadata)

        if refresh_external_db_file and self._should_download_external_db(remote_metadata):
            print("Downloading External Audio Source SQLite database...")
            try:
                self._download_file(
                    f"{self.url}/{self.EXTERNAL_DB_FILE_NAME}", self.external_audio_db_path, "External Audio Source SQLite DB"
                )
                self._update_local_metadata(remote_metadata)
            except Exception as e:
                print(f"Failed to download external database: {e}.")

        with open(self.chunks_manifest_json_path, "r") as f:
            json_manifest = json.load(f)
            self.mapped_manifest = {group["id"]: group for group in json_manifest}

        for group_id, group in self.mapped_manifest.items():
            parquet_url = group["last_export_filename"]
            parquet_filename = self._extract_dataset_audio_chunks_file_name(parquet_url)
            parquet_path = self.cache_dir / parquet_filename

            if not parquet_path.exists():
                print(f"Downloading {parquet_filename}...")
                self._download_file(parquet_url, parquet_path, parquet_filename)

            # Map the path the local parquet file
            self.mapped_manifest[group_id]["_parquet_path"] = parquet_path

    def _extract_dataset_audio_chunks_file_name(self, last_export_filename_url: str) -> str:
        return last_export_filename_url.split("/")[-1]

    def _refresh_json_manifest_and_dataset_audio_chunks(self):
        if self.chunks_manifest_json_path.exists():
            self.chunks_manifest_json_path.unlink()
        self._sync(refresh_chunks_manifest_json_file=True)

    def _download_file(self, url: str, filepath: Path, desc=None):
        response = requests.get(url, stream=True)
        response.raise_for_status()
        total_size = int(response.headers.get("content-length", 0))
        block_size = 1024 * 8

        with tqdm(total=total_size, unit="B", unit_scale=True, desc=desc) as pbar:
            with open(filepath, "wb") as f:
                for buffer in response.iter_content(block_size):
                    f.write(buffer)
                    pbar.update(len(buffer))

    def get_dataset_audio_chunk_groups(self, should_refresh_local_cache: bool = False) -> pd.DataFrame:
        if should_refresh_local_cache:
            self._refresh_json_manifest_and_dataset_audio_chunks()

        return pd.DataFrame(list(self.mapped_manifest.values()))

    def build_dataset(
        self,
        id: int,
        n_fft: int,
        hop_length: int,
        win_length: int,
        n_mels: int,
        *,
        pad_mode: Literal["zero", "windowed_repeat"] = "zero",
        partition_type: Literal["train", "validation", "test"] | None = None,
        pitch_shift_prob: float = 0.0,
        enable_spec_augment: bool = False,
        speaker_ids_filter: list[str] | None = None,
        should_refresh_local_cache: bool = True,
        emotion_columns_override: list[str] | None = None,
        emotions_merger: Callable | None = None,
    ) -> AudioChunksDataset:
        # Partition type or speaker_ids_filter override validation.
        if partition_type and speaker_ids_filter:
            raise ValueError("`speaker_ids_filter` is not valid when `partition_type` argument is provided")
        elif partition_type and id >= self.DATASET_AUDIO_CHUNK_GROUP_ID_INWORLD_CUTOFF:
            # Add external audio chunks for dataset_audio_chunk_group_id >= 8
            speaker_ids_filter = (
                self.IEMOCAP_SPEAKERS_PARTITIONS[partition_type]
                + self.EXTERNAL_AUDIO_SPEAKERS_PARTITIONS[partition_type]
            )
        elif partition_type:
            speaker_ids_filter = self.IEMOCAP_SPEAKERS_PARTITIONS[partition_type]

        # Emotion columns overrides and emotion merger function validation.
        if (emotion_columns_override is None) != (emotions_merger is None):
            raise ValueError("Both 'emotion_columns_override' and 'emotions_merger' must be provided together.")

        if enable_spec_augment and partition_type is not None and partition_type != "train":
            raise ValueError("SpecAugment should only be applied to the 'train' split.")

        if pitch_shift_prob > 0 and partition_type is not None and partition_type != "train":
            raise ValueError("Pitch shift should only be applied to the 'train' split.")

        if should_refresh_local_cache:
            self._refresh_json_manifest_and_dataset_audio_chunks()

        # Find the group
        group = self.mapped_manifest[id]

        parquet_url = group["last_export_filename"]
        parquet_filename = self._extract_dataset_audio_chunks_file_name(parquet_url)
        parquet_path = self.cache_dir / parquet_filename

        schema = pq.read_schema(parquet_path)
        field_idx = schema.names.index('should_exclude')
        should_exclude_type = schema.types[field_idx]

        # If it is not boolean (e.g. it is integer/numeric),
        # we compare against 0. Otherwise, we compare against False.
        exclude_val = False
        if not pa.types.is_boolean(should_exclude_type):
            exclude_val = 0

        filters = [
            [('should_exclude', '==', exclude_val)],  # Condition 1
        ]
        if speaker_ids_filter:
            # AND Condition 2
            filters[0].append(('speaker_id', 'in', speaker_ids_filter))

        df = pd.read_parquet(parquet_path, filters=filters)
        df = df[df["should_exclude"] == False].copy()
        df = df.reset_index(drop=True)

        if emotions_merger is None and not df.empty:
            if id >= self.DATASET_AUDIO_CHUNK_GROUP_ID_INWORLD_CUTOFF:
                # Load Inworld emotions for id (dataset_audio_chunk_group_id) >= 8
                emotion_columns_override = AudioChunksDataset.INWORLD_EMOTIONS
            elif id >= self.DATASET_AUDIO_CHUNK_GROUP_ID_V2_CUTOFF:
                # Load default emotions merger for id (dataset_audio_chunk_group_id) >= 2
                emotions_merger = merge_emotions_by_row_v1
                emotion_columns_override = AudioChunksDataset.LABELS_EMOTIONS_V2

        if emotions_merger:
            # Create new columns by applying the function.
            new_features_df = df.apply(emotions_merger, axis=1)

            # Join the new columns back to the original DataFrame.
            df = pd.concat([df, new_features_df], axis=1)

        return AudioChunksDataset(
            df_dataset_audio_chunks=df,
            iemocap_db_path=self.iemocap_db_path,
            external_audio_db_path=self.external_audio_db_path,
            sample_rate=group["sample_rate"],
            chunk_threshold_seconds=group["chunk_threshold_seconds"],
            n_fft=n_fft,
            hop_length=hop_length,
            win_length=win_length,
            n_mels=n_mels,
            pad_mode=pad_mode,
            pitch_shift_prob=pitch_shift_prob,
            enable_spec_augment=enable_spec_augment,
            emotion_columns_override=emotion_columns_override,
        )

